request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?model
  ?modelName
  ?modelCreated
  ?originalId
  ?normalizedId
WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "38b17e822a5e4307ae051694293e4d0f" .
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:modelCreated ?modelCreated ;
         tai:originalId ?originalId ;
         tai:normalizedId ?normalizedId .

  # financial task heuristic: tasks with name containing common financial keywords
  ?choreo a bboExt:Choreography .
  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .
  FILTER(
    EXISTS {
      FILTER(CONTAINS(LCASE(STR(?taskName)), "pay"))
    }
    || EXISTS {
      FILTER(CONTAINS(LCASE(STR(?taskName)), "payment"))
    }
    || EXISTS {
      FILTER(CONTAINS(LCASE(STR(?taskName)), "invoice"))
    }
    || EXISTS {
      FILTER(CONTAINS(LCASE(STR(?taskName)), "bank"))
    }
    || EXISTS {
      FILTER(CONTAINS(LCASE(STR(?taskName)), "finance"))
    }
    || EXISTS {
      FILTER(CONTAINS(LCASE(STR(?taskName)), "loan"))
    }
    || EXISTS {
      FILTER(CONTAINS(LCASE(STR(?taskName)), "credit"))
    }
  )

  FILTER EXISTS {
    ?defs tai:belongsTo ?model .
    ?choreo tai:belongsTo ?defs .
  }
}
ORDER BY DESC(?modelCreated)
LIMIT 25
